using System;\nusing System.Windows;\nusing SimpleScreenBot.Services;\nusing BotAutomation;\nnamespace SimpleScreenBot {\n    public partial class MainWindow : Window {\n        private BotEngine _botEngine;\n        private ConfigManager _configManager;\n        private bool _isRunning;\n        public MainWindow() {\n            InitializeComponent();\n            InitializeBot();\n        }\n        private void InitializeBot() {\n            try {\n                _botEngine = new BotEngine();\n                _configManager = new ConfigManager("rules.json");\n                _isRunning = false;\n                Title = "Simple Screen Bot - Ready";\n            } catch (Exception ex) {\n                MessageBox.Show($"Error initializing bot: {ex.Message}", "Error", MessageBoxButton.OK, MessageBoxImage.Error);\n            }\n        }\n        public void LogMessage(string message) {\n            string timestamp = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");\n            Console.WriteLine($"[{timestamp}] {message}");\n        }\n    }\n}